import Payze from '@payze/node';

const payze = new Payze('sk_live_...');

const payment = await payze.payments.create({
  amount: 7800,
  currency: 'INR',
  method: 'auto',
  customer: { email: 'priya@example.com' },
  fallback: ['upi', 'netbanking', 'wallet'],
  metadata: { order_id: 'ord_8374' }
});

console.log(payment.id, payment.status);

